void rwlock_init(RWLock *lock) {
    // Your implementation
}

bool rwlock_read_acquire(RWLock *lock) {
    // Acquire read lock: succeed if no writer is active
    return false;
}

void rwlock_read_release(RWLock *lock) {
    // Release read lock
}

bool rwlock_write_acquire(RWLock *lock) {
    // Acquire write lock: succeed only if no readers AND no writer
    return false;
}

void rwlock_write_release(RWLock *lock) {
    // Release write lock
}

int main() {
    RWLock lock;
    rwlock_init(&lock);

    // Multiple readers should succeed
    printf("Read 1: %s\n", rwlock_read_acquire(&lock) ? "acquired" : "blocked");
    printf("Read 2: %s\n", rwlock_read_acquire(&lock) ? "acquired" : "blocked");
    printf("Read 3: %s\n", rwlock_read_acquire(&lock) ? "acquired" : "blocked");
    printf("Readers active: %d\n", lock.reader_count);

    // Writer should fail while readers active
    printf("Write (readers active): %s\n",
           rwlock_write_acquire(&lock) ? "acquired" : "blocked");

    // Release all readers
    rwlock_read_release(&lock);
    rwlock_read_release(&lock);
    rwlock_read_release(&lock);

    // Now writer should succeed
    printf("Write (no readers): %s\n",
           rwlock_write_acquire(&lock) ? "acquired" : "blocked");

    // Reader should fail while writer active
    printf("Read (writer active): %s\n",
           rwlock_read_acquire(&lock) ? "acquired" : "blocked");

    // Release writer, readers should work again
    rwlock_write_release(&lock);
    printf("Read (after write release): %s\n",
           rwlock_read_acquire(&lock) ? "acquired" : "blocked");

    return 0;
}
